1	/**
2	 * Axios API client.
3	 * - Base URL: /api/v1/
4	 * - Reads CSRF token from the `csrftoken` cookie and sends it as X-CSRFToken header
5	 * - Sends credentials (session cookie) with every request
6	 * - Attaches DRF Token auth header when a token is stored in sessionStorage
7	 *
8	 * Anti-tampering / request integrity:
9	 * The combination of CSRF token (prevents cross-site request forgery) and Bearer
10	 * token (ensures only authenticated clients mutate state) is the accepted security
11	 * model for this application. Per-request HMAC signing is not used: a shared secret
12	 * embedded in client-side JS would be visible to all users and add no real security
13	 * beyond what CSRF + token auth already provide. See docs/design.md §8.
14	 */
15	import axios from "axios";
16	
17	function getCookie(name: string): string | null {
18	  const match = document.cookie.match(new RegExp("(^|;\\s*)" + name + "=([^;]*)"));
19	  return match ? decodeURIComponent(match[2]) : null;
20	}
21	
22	const apiClient = axios.create({
23	  baseURL: "/api/v1/",
24	  withCredentials: true,       // send session cookie
25	  headers: {
26	    "Content-Type": "application/json",
27	    Accept: "application/json",
28	  },
29	});
30	
31	// Attach CSRF token and optional Bearer token before every mutating request
32	apiClient.interceptors.request.use((config) => {
33	  const csrf = getCookie("csrftoken");
34	  if (csrf) {
35	    config.headers["X-CSRFToken"] = csrf;
36	  }
37	
38	  const token = sessionStorage.getItem("auth_token");
39	  if (token) {
40	    config.headers["Authorization"] = `Token ${token}`;
41	  }
42	
43	  return config;
44	});
45	
46	// Normalise error shape + global status handling
47	apiClient.interceptors.response.use(
48	  (response) => response,
49	  (error) => {
50	    const status = error.response?.status;
51	
52	    // 401 — session expired, redirect to login
53	    if (status === 401) {
54	      sessionStorage.removeItem("auth_token");
55	      if (window.location.pathname !== "/login") {
56	        window.location.href = "/login";
57	      }
58	      return Promise.reject(error);
59	    }
60	
61	    // 429 — rate limited, surface Retry-After in message
62	    if (status === 429) {
63	      const retryAfter = error.response?.headers?.["retry-after"];
64	      const msg = retryAfter
65	        ? `Too many requests. Please wait ${retryAfter} seconds.`
66	        : "Too many requests. Please wait a moment.";
67	      const enhanced = new Error(msg);
68	      (enhanced as any).status = 429;
69	      (enhanced as any).response = error.response;
70	      return Promise.reject(enhanced);
71	    }
72	
73	    // 500 — server error
74	    if (status >= 500) {
75	      const enhanced = new Error("Something went wrong. Please try again.");
76	      (enhanced as any).status = status;
77	      (enhanced as any).response = error.response;
78	      return Promise.reject(enhanced);
79	    }
80	
81	    // Other structured errors
82	    const serverError = error.response?.data?.error;
83	    if (serverError) {
84	      const enhanced = new Error(serverError.message ?? "An error occurred");
85	      (enhanced as any).code    = serverError.code;
86	      (enhanced as any).detail  = serverError.detail;
87	      (enhanced as any).status  = status;
88	      (enhanced as any).response = error.response;
89	      return Promise.reject(enhanced);
90	    }
91	
92	    return Promise.reject(error);
93	  }
94	);
95	
96	export default apiClient;
